INSERT INTO news (title, category, author, publish_date, content, description, cover_image, status, is_top, is_headline, sort_order, created_at, updated_at) VALUES
-- 近期党建动态
('我校开展“学习贯彻党的二十大精神”主题党日活动', '党建工作', '组织部', NOW() - INTERVAL 5 DAY, '1月12日，我校各党支部开展了“学习贯彻党的二十大精神”主题党日活动。活动中，各党支部组织党员认真学习了党的二十大报告和党章，观看了相关学习视频，并结合工作实际进行了交流讨论。通过此次主题党日活动，广大党员干部的思想政治觉悟得到了进一步提高，干事创业的热情得到了进一步激发。', '我校各党支部开展“学习贯彻党的二十大精神”主题党日活动，推动党的二十大精神深入人心。', 'https://example.com/cover2.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校党建工作获得上级表彰', '党建工作', '组织部', NOW() - INTERVAL 8 DAY, '近日，我校党建工作获得上级表彰，被评为“2023年度党建工作先进单位”。这一荣誉是对我校党建工作的充分肯定，也是对全体党员干部的激励和鞭策。校党委书记表示，学校将以此为契机，进一步加强党建工作，推动学校各项事业高质量发展。', '我校党建工作获得上级表彰，被评为“2023年度党建工作先进单位”。', 'https://example.com/cover3.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期教学工作
('我校教师在省级教学技能大赛中获得佳绩', '教学工作', '教务处', NOW() - INTERVAL 4 DAY, '1月13日，2023年省级高校教师教学技能大赛结果揭晓，我校共有10名教师获奖，其中一等奖3名，二等奖4名，三等奖3名。这是我校在省级教学技能大赛中取得的历史最好成绩，充分展示了我校教师的教学水平和专业素养。', '我校教师在省级教学技能大赛中获得佳绩，10名教师获奖。', 'https://example.com/cover5.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校开展2024年春季学期教学准备工作检查', '教学工作', '教务处', NOW() - INTERVAL 7 DAY, '1月10日，我校组织开展了2024年春季学期教学准备工作检查。检查小组对各学院的教学计划制定、教材准备、教师安排等情况进行了全面检查，并提出了改进意见和建议。通过此次检查，确保了春季学期教学工作的顺利开展。', '我校开展2024年春季学期教学准备工作检查，确保教学工作顺利开展。', 'https://example.com/cover6.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期科研成果
('我校获批多项国家级科研项目', '科研成果', '科研处', NOW() - INTERVAL 6 DAY, '近日，国家自然科学基金委员会公布了2024年度国家自然科学基金项目立项名单，我校共有15项项目获批立项，其中面上项目8项，青年科学基金项目7项。这些项目的获批，充分体现了我校在相关领域的科研实力和学术水平。', '我校获批15项国家级科研项目，科研工作取得新进展。', 'https://example.com/cover8.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校举办2024年科研工作会议', '科研成果', '科研处', NOW() - INTERVAL 9 DAY, '1月9日，我校在图书馆报告厅举办了2024年科研工作会议。会议总结了学校2023年的科研工作，表彰了先进集体和个人，并部署了2024年的科研工作任务。校长在讲话中强调，要进一步加强科研工作，提高科研水平和创新能力，为学校的发展提供有力支撑。', '我校举办2024年科研工作会议，部署新一年科研工作任务。', 'https://example.com/cover9.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期学生活动
('我校举办2024年元旦文艺晚会', '学生活动', '团委', NOW() - INTERVAL 14 DAY, '12月31日，我校在体育馆举办了2024年元旦文艺晚会。晚会以“青春梦想·共创未来”为主题，节目形式多样，内容丰富，充分展示了我校学生的才艺和风采。校领导、师生代表及部分校友观看了晚会。', '我校举办2024年元旦文艺晚会，展现学生青春风采。', 'https://example.com/cover10.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校学生在全国大学生数学建模竞赛中获奖', '学生活动', '学生处', NOW() - INTERVAL 12 DAY, '近日，2023年全国大学生数学建模竞赛结果揭晓，我校共有8支参赛队伍获奖，其中一等奖2项，二等奖3项，三等奖3项。这是我校在全国大学生数学建模竞赛中取得的又一佳绩，充分展示了我校学生的创新能力和团队协作精神。', '我校学生在全国大学生数学建模竞赛中获得8项奖项。', 'https://example.com/cover11.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校开展2024年寒假社会实践活动', '学生活动', '学生处', NOW() - INTERVAL 15 DAY, '近日，我校启动了2024年寒假社会实践活动。本次活动以“青春建功新时代·志愿服务暖人心”为主题，组织学生深入社区、乡村开展志愿服务、调研走访等活动。通过此次活动，引导学生在实践中增长才干，服务社会。', '我校启动2024年寒假社会实践活动，引导学生服务社会。', 'https://example.com/cover12.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期校园动态
('我校举行2023年秋季学期开学典礼', '校园动态', '校长办公室', NOW() - INTERVAL 3 DAY, '1月16日，我校在体育场举行了2023年秋季学期开学典礼。校长在典礼上发表了热情洋溢的讲话，鼓励全体师生在新的学期里以饱满的热情投入到学习和工作中，为学校的发展贡献自己的力量。', '我校举行2023年秋季学期开学典礼，校长发表讲话。', 'https://example.com/cover14.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校图书馆新馆正式开馆', '校园动态', '图书馆', NOW() - INTERVAL 10 DAY, '1月6日，我校图书馆新馆正式开馆。新馆建筑面积达2万平方米，藏书量超过100万册，配备了先进的数字化设备和舒适的阅读环境。图书馆新馆的开馆，将为师生提供更好的学习和研究条件。', '我校图书馆新馆正式开馆，提供更好的学习研究条件。', 'https://example.com/cover15.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期国际交流
('我校与国外高校签署合作协议', '国际交流', '国际合作与交流处', NOW() - INTERVAL 1 DAY, '1月18日，我校与美国某知名高校签署了校际合作协议。根据协议，两校将在学生交换、教师互访、科研合作等方面开展深入合作。此次合作协议的签署，标志着我校的国际交流与合作迈上新的台阶。', '我校与国外高校签署合作协议，国际交流合作迈上新台阶。', 'https://example.com/cover17.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校举办国际学术研讨会', '国际交流', '国际合作与交流处', NOW() - INTERVAL 5 DAY, '1月13日，我校举办了“人工智能与未来教育”国际学术研讨会。来自国内外多所高校和研究机构的专家学者参加了研讨会，围绕人工智能在教育领域的应用进行了深入探讨和交流。', '我校举办“人工智能与未来教育”国际学术研讨会，促进学术交流。', 'https://example.com/cover18.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期就业信息
('我校举办2024届毕业生春季招聘会', '就业信息', '就业指导中心', NOW() - INTERVAL 4 DAY, '1月14日，我校举办了2024届毕业生春季招聘会。来自全国各地的200余家企业参加了招聘会，提供了5000余个就业岗位。招聘会现场气氛热烈，毕业生们积极与用人单位交流，寻找适合自己的工作岗位。', '我校举办2024届毕业生春季招聘会，提供5000余个就业岗位。', 'https://example.com/cover20.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校毕业生就业率保持较高水平', '就业信息', '就业指导中心', NOW() - INTERVAL 11 DAY, '近日，我校发布了2023届毕业生就业质量报告。报告显示，我校2023届毕业生就业率达到95.2%，其中本科毕业生就业率为94.8%，研究生毕业生就业率为96.5%。这一数据充分体现了我校毕业生的就业竞争力和社会认可度。', '我校2023届毕业生就业率达到95.2%，就业质量稳步提升。', 'https://example.com/cover21.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期安全工作
('我校开展消防安全知识培训', '安全工作', '保卫处', NOW() - INTERVAL 6 DAY, '1月12日，我校邀请消防专家为全体教职工和学生代表开展了消防安全知识培训。培训内容包括火灾预防、灭火器使用、逃生自救等方面的知识。通过此次培训，增强了师生的消防安全意识和应急处置能力。', '我校开展消防安全知识培训，增强师生安全意识。', 'https://example.com/cover23.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校开展校园安全隐患排查', '安全工作', '保卫处', NOW() - INTERVAL 9 DAY, '1月9日，我校组织开展了校园安全隐患排查工作。排查小组对校园内的教学楼、宿舍、食堂、实验室等场所进行了全面检查，及时消除了安全隐患，确保了校园安全稳定。', '我校开展校园安全隐患排查，确保校园安全稳定。', 'https://example.com/cover24.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期后勤服务
('我校学生宿舍热水供应系统升级改造完成', '后勤服务', '后勤处', NOW() - INTERVAL 3 DAY, '近日，我校学生宿舍热水供应系统升级改造工程顺利完成。新的热水供应系统采用了先进的空气能热泵技术，具有节能、环保、安全等优点。升级改造后，学生宿舍的热水供应更加稳定，水温更加适宜，为学生提供了更好的生活条件。', '我校学生宿舍热水供应系统升级改造完成，提升学生生活条件。', 'https://example.com/cover28.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校食堂推出新菜品', '后勤服务', '后勤处', NOW() - INTERVAL 7 DAY, '1月10日，我校食堂推出了一系列新菜品。新菜品包括地方特色菜、健康营养菜、民族风味菜等，种类丰富，口味多样，受到了师生的欢迎。食堂负责人表示，将继续推出更多新菜品，满足师生的饮食需求。', '我校食堂推出新菜品，丰富师生饮食选择。', 'https://example.com/cover29.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期学术讲座
('我校举办“大数据时代的信息安全”学术讲座', '学术讲座', '信息科学与工程学院', NOW() - INTERVAL 2 DAY, '1月16日，我校邀请国内知名信息安全专家为师生作了题为“大数据时代的信息安全”的学术讲座。讲座深入分析了大数据时代信息安全面临的挑战和机遇，并探讨了如何加强信息安全防护。', '我校举办“大数据时代的信息安全”学术讲座，提升信息安全意识。', 'https://example.com/cover31.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校举办“中国传统文化与当代社会”学术讲座', '学术讲座', '人文学院', NOW() - INTERVAL 8 DAY, '1月11日，我校邀请著名学者为师生作了题为“中国传统文化与当代社会”的学术讲座。讲座从多个角度探讨了中国传统文化的当代价值和意义，引导师生正确认识和传承中华优秀传统文化。', '我校举办“中国传统文化与当代社会”学术讲座，传承中华优秀传统文化。', 'https://example.com/cover32.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期校园文化
('我校举办校园文化艺术节', '校园文化', '团委', NOW() - INTERVAL 6 DAY, '1月12日，我校举办了为期一周的校园文化艺术节。艺术节期间，举办了书法绘画展、摄影展、演讲比赛、辩论赛等多项活动，丰富了校园文化生活，展示了我校学生的综合素质和艺术才华。', '我校举办校园文化艺术节，丰富校园文化生活。', 'https://example.com/cover34.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校学生在全省大学生艺术展演中获奖', '校园文化', '团委', NOW() - INTERVAL 13 DAY, '近日，2023年全省大学生艺术展演结果揭晓，我校共有12个节目获奖，其中一等奖4个，二等奖5个，三等奖3个。这些节目涵盖了舞蹈、音乐、戏剧、书画等多个艺术门类，充分展示了我校学生的艺术才华和创造力。', '我校学生在全省大学生艺术展演中获得12项奖项。', 'https://example.com/cover35.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期工会工作
('我校举办教职工趣味运动会', '工会工作', '工会', NOW() - INTERVAL 11 DAY, '1月9日，我校举办了教职工趣味运动会。运动会设有拔河、跳绳、踢毽子、趣味接力等多个项目，广大教职工积极参与，展现了良好的精神风貌。此次运动会丰富了教职工的业余生活，增强了教职工的身体素质和团队协作精神。', '我校举办教职工趣味运动会，丰富教职工业余生活。', 'https://example.com/cover41.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校组织教职工健康体检', '工会工作', '工会', NOW() - INTERVAL 8 DAY, '1月11日，我校组织全体教职工进行了健康体检。体检项目包括血常规、尿常规、肝功能、肾功能、心电图、胸部CT等，全面检查教职工的身体健康状况。学校高度重视教职工的身体健康，定期组织健康体检，体现了对教职工的关怀。', '我校组织教职工健康体检，关怀教职工身体健康。', 'https://example.com/cover42.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期校友工作
('我校校友捐赠设立奖学金', '校友工作', '校友办', NOW() - INTERVAL 3 DAY, '近日，我校90届校友张先生向母校捐赠100万元，设立“励志奖学金”，用于奖励品学兼优的家庭经济困难学生。张先生表示，希望通过设立奖学金，帮助更多的学生顺利完成学业，实现自己的人生梦想。', '我校校友捐赠设立奖学金，支持母校教育事业发展。', 'https://example.com/cover43.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),
('我校举办校友返校日活动', '校友工作', '校友办', NOW() - INTERVAL 6 DAY, '1月12日，我校举办了校友返校日活动。来自各地的校友重返母校，参观校园，与师生交流，回忆校园生活。校友返校日活动的举办，加强了校友与母校之间的联系，促进了校友之间的交流与合作。', '我校举办校友返校日活动，加强校友与母校联系。', 'https://example.com/cover44.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW()),

-- 近期信息化建设
('我校智慧校园平台正式上线', '信息化建设', '信息化办公室', NOW() - INTERVAL 7 DAY, '1月10日，我校智慧校园平台正式上线。平台集成了教学、科研、管理、服务等多个系统，实现了信息资源的共享和业务流程的优化。智慧校园平台的上线，标志着我校的信息化建设水平达到了一个新的高度，为学校的发展提供了有力的技术支撑。', '我校智慧校园平台正式上线，信息化建设水平再上新台阶。', 'https://example.com/cover45.jpg', 'published', FALSE, FALSE, 0, NOW(), NOW());
